        /* 填充狀態欄數據 */
        function populateCharacterData() {
            try {
                const all_variables = getAllVariables();
                const data = all_variables.stat_data;

                if (!data) {
                    $('#status-card').html("<div class='error-tip'>無法加載狀態數據 (data is null)</div>");
                    return;
                }

                /* 填充世界資訊 */
                $('#world-date').text(`${_.get(data, '世界.年分', 'N/A')}/${_.get(data, '世界.月份', 'N/A')}/${_.get(data, '世界.日期', 'N/A')} (${_.get(data, '世界.星期', 'N/A')})`);
                $('#world-time').text(_.get(data, '世界.時間', 'N/A'));

                /* 填充靜香頁面 */
                $('#shizuka-location').text(_.get(data, '靜香.當前地點', 'N/A'));
                $('#shizuka-outfit').text(_.get(data, '靜香.當前打扮', 'N/A'));
                $('#shizuka-action').text(_.get(data, '靜香.當前行動', 'N/A'));
                $('#shizuka-next-action').text(_.get(data, '靜香.下一步行動', 'N/A'));
                $('#shizuka-thoughts').text(_.get(data, '靜香.心聲', 'N/A'));

                /* 填充聖域頁面 */
                $('#sanctuary-cycle').text(_.get(data, '聖域.月經週期', 'N/A'));
                $('#sanctuary-womb').text(_.get(data, '聖域.子宮狀態', 'N/A'));
                $('#sanctuary-pregnant').text(_.get(data, '聖域.是否懷孕', false) ? '是' : '否');
                $('#sanctuary-gestation').text(`${_.get(data, '聖域.懷孕週期', 0)} 週`);
                $('#sanctuary-births').text(_.get(data, '聖域.生產次數', 0));

            } catch (error) {
                console.error("狀態欄載入出錯:", error);
                $('#status-card').html(`<div class='error-tip'>狀態欄渲染時發生錯誤: ${error.message}</div>`);
            }
        }

        /* 切换标签 */
        function switchTab(tabName) {
            $('.tab-button').removeClass('active');
            $('.tab-panel').removeClass('active');
            $(`[data-tab="${tabName}"]`).addClass('active');
            $(`#tab-content-${tabName}`).addClass('active');
        }

        /* 初始化 */
        async function init() {
            await waitGlobalInitialized('Mvu');
            populateCharacterData();

            /* 綁定標籤切換事件 */
            $('.tab-button').on('click', function () {
                const tabName = $(this).data('tab');
                switchTab(tabName);
            });

            /* 默認顯示第一個標籤 */
            switchTab('shizuka');
        }

        $(errorCatched(init));
    </script>
