import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  世界: z.object({
    年分: z.coerce.number(),
    月份: z.coerce.number(),
    星期: z.string(),
    日期: z.coerce.number(),
    時間: z.string().regex(/^\d{2}:\d{2}$/).describe('HH:MM 格式'),
  }),
  靜香: z.object({
    當前地點: z.string(),
    當前打扮: z.string(),
    當前行動: z.string(),
    下一步行動: z.string(),
    心聲: z.string().describe('靜香不為人知的內心想法，通常與對兒子的關心、慾望或無奈有關'),
  }),
  聖域: z.object({
    月經週期: z.enum(["安全期", "排卵期", "經期", "未知"]),
    子宮狀態: z.string(),
    是否懷孕: z.boolean(),
    懷孕週期: z.coerce.number().describe('以週為單位'),
    生產次數: z.coerce.number(),
  }),
});

$(() => {
  registerMvuSchema(Schema);
})
